// booking_payment_messages.go — hand-written proto message types for the
// MarkBookingPaid RPC that payment-svc calls on booking-svc.
//
// NOTE: These types would normally be generated by protoc from booking.proto.
// They are written by hand here because protoc is not available in the sandbox.
// Once booking-svc.proto is updated and `make genpb` is run, delete this file
// and import the generated pb package instead.
//
// Wire contract: payment-svc → booking-svc.MarkBookingPaid(booking_id, amount, invoice_status).
// booking-svc transitions the booking state accordingly.

package pb

// ---------------------------------------------------------------------------
// MarkBookingPaidRequest
// ---------------------------------------------------------------------------

// MarkBookingPaidRequest is sent by payment-svc to booking-svc when an invoice
// payment event is processed (webhook or reconciliation backfill).
type MarkBookingPaidRequest struct {
	// BookingID is the booking.bookings.id (TEXT / prefixed ULID format).
	BookingID string
	// AmountPaidIDR is the running paid_amount on the invoice (IDR, cents precision).
	AmountPaidIDR float64
	// InvoiceStatus reflects the invoice's new status after the event
	// ("partially_paid" | "paid").
	InvoiceStatus string
	// InvoiceID is payment-svc's invoice.id (UUID string) for reference.
	InvoiceID string
}

func (x *MarkBookingPaidRequest) GetBookingId() string {
	if x == nil {
		return ""
	}
	return x.BookingID
}
func (x *MarkBookingPaidRequest) GetAmountPaidIdr() float64 {
	if x == nil {
		return 0
	}
	return x.AmountPaidIDR
}
func (x *MarkBookingPaidRequest) GetInvoiceStatus() string {
	if x == nil {
		return ""
	}
	return x.InvoiceStatus
}
func (x *MarkBookingPaidRequest) GetInvoiceId() string {
	if x == nil {
		return ""
	}
	return x.InvoiceID
}

// ---------------------------------------------------------------------------
// MarkBookingPaidResponse
// ---------------------------------------------------------------------------

// MarkBookingPaidResponse is returned by booking-svc on success.
type MarkBookingPaidResponse struct {
	// BookingID echoes the input.
	BookingID string
	// NewStatus is the booking's status after the transition.
	NewStatus string
}

func (x *MarkBookingPaidResponse) GetBookingId() string {
	if x == nil {
		return ""
	}
	return x.BookingID
}
func (x *MarkBookingPaidResponse) GetNewStatus() string {
	if x == nil {
		return ""
	}
	return x.NewStatus
}

// ---------------------------------------------------------------------------
// Minimal client stub (hand-written; replaces protoc-generated _grpc.pb.go)
// ---------------------------------------------------------------------------

// BookingServiceClient is the minimal interface used by payment-svc.
// The full generated interface lives in booking-svc/api/grpc_api/pb/booking_grpc.pb.go.
type BookingServiceClient interface {
	MarkBookingPaid(req *MarkBookingPaidRequest) (*MarkBookingPaidResponse, error)
}
